INSERT INTO board (created_at, updated_at, content, district, is_rewarded, like_count, title, view_count, user_id) VALUES
                                                                                                                       ('2026-04-01 10:00:00', '2026-04-01 10:00:00', '우리 동네 횡단보도가 너무 짧아서 노인분들이 건너기 힘드세요. 신호등 시간을 늘려주셨으면 합니다.', '서울시 강남구', 0, 5, '횡단보도 신호 시간 연장 요청', 12, 1),
                                                                                                                       ('2026-04-01 11:00:00', '2026-04-01 11:00:00', '강남구 공원에 쓰레기통이 부족합니다. 특히 주말에 사람이 많이 몰리는 구역에는 꼭 설치해주세요.', '서울시 서초구', 0, 8, '공원 쓰레기통 추가 설치 요청', 20, 2),
                                                                                                                       ('2026-04-01 12:00:00', '2026-04-01 12:00:00', '골목길 가로등이 고장난 지 한 달이 넘었습니다. 밤에 다니기 너무 무섭습니다. 빠른 수리 부탁드립니다.', '서울시 마포구', 0, 3, '골목길 가로등 수리 요청', 8, 3),
                                                                                                                       ('2026-04-02 09:00:00', '2026-04-02 09:00:00', '지역 내 주차 공간이 너무 부족합니다. 공영주차장 확충이 시급합니다.', '서울시 송파구', 0, 15, '공영주차장 확충 건의', 35, 1),
                                                                                                                       ('2026-04-02 10:00:00', '2026-04-02 10:00:00', '어린이 보호구역인데 과속 차량이 너무 많습니다. 단속 카메라 설치를 요청드립니다.', '서울시 강서구', 0, 22, '어린이 보호구역 단속 카메라 설치', 48, 2),
                                                                                                                       ('2026-04-02 11:00:00', '2026-04-02 11:00:00', '지역 내 버스 배차 간격이 너무 깁니다. 출퇴근 시간대에는 최소 5분 간격으로 운행해주세요.', '서울시 노원구', 0, 9, '버스 배차 간격 단축 요청', 19, 3),
                                                                                                                       ('2026-04-03 09:00:00', '2026-04-03 09:00:00', '동네 하천 산책로가 정비가 안 되어 있습니다. 주민들이 자주 이용하는 곳인데 개선이 필요합니다.', '서울시 은평구', 0, 6, '하천 산책로 정비 요청', 14, 1),
                                                                                                                       ('2026-04-03 10:00:00', '2026-04-03 10:00:00', '복지관 노인 프로그램이 너무 적습니다. 다양한 여가 활동 프로그램을 늘려주셨으면 합니다.', '서울시 도봉구', 0, 11, '복지관 노인 프로그램 확대 건의', 27, 2),
                                                                                                                       ('2026-04-03 11:00:00', '2026-04-03 11:00:00', '지역 내 청년 일자리 지원 센터가 없습니다. 취업 정보 제공 및 상담 공간이 필요합니다.', '서울시 성동구', 0, 18, '청년 일자리 지원 센터 설치 요청', 42, 3),
                                                                                                                       ('2026-04-04 09:00:00', '2026-04-04 09:00:00', '아파트 단지 내 분리수거 시설이 노후화되었습니다. 교체 및 정비가 필요합니다.', '서울시 광진구', 0, 4, '분리수거 시설 정비 요청', 9, 1),
                                                                                                                       ('2026-04-04 10:00:00', '2026-04-04 10:00:00', '동네 도서관 운영 시간이 너무 짧습니다. 저녁 10시까지 연장 운영해주시면 좋겠습니다.', '서울시 동작구', 0, 13, '도서관 운영 시간 연장 건의', 31, 2),
                                                                                                                       ('2026-04-04 11:00:00', '2026-04-04 11:00:00', '학교 앞 불법 주정차가 심각합니다. 등하교 시간대 집중 단속이 필요합니다.', '서울시 관악구', 0, 7, '학교 앞 불법 주정차 단속 강화', 16, 3),
                                                                                                                       ('2026-04-05 09:00:00', '2026-04-05 09:00:00', '지역 내 공중화장실이 부족하고 위생 상태도 좋지 않습니다. 시설 개선이 필요합니다.', '서울시 중랑구', 0, 2, '공중화장실 시설 개선 요청', 6, 1),
                                                                                                                       ('2026-04-05 10:00:00', '2026-04-05 10:00:00', '전통 시장 주변 도로가 너무 협소합니다. 보행자와 차량 동선 분리가 필요합니다.', '서울시 영등포구', 0, 16, '전통시장 주변 도로 정비 건의', 38, 2),
                                                                                                                       ('2026-04-05 11:00:00', '2026-04-05 11:00:00', '우리 동네에 편의시설이 부족합니다. 특히 은행 ATM이 없어서 불편합니다.', '서울시 구로구', 0, 10, '편의시설 확충 요청', 23, 3),
                                                                                                                       ('2026-04-06 09:00:00', '2026-04-06 09:00:00', '지역 축제나 문화 행사가 너무 없습니다. 주민 화합을 위한 행사를 기획해주세요.', '서울시 강북구', 0, 21, '지역 문화 행사 개최 건의', 52, 1),
                                                                                                                       ('2026-04-06 10:00:00', '2026-04-06 10:00:00', '자전거 도로가 중간에 끊겨 있어 위험합니다. 연속성 있는 자전거 도로 구축이 필요합니다.', '서울시 성북구', 0, 14, '자전거 도로 연결 구축 요청', 33, 2),
                                                                                                                       ('2026-04-06 11:00:00', '2026-04-06 11:00:00', '지역 내 반려동물 놀이터가 없습니다. 공원 한 켠에 반려동물 전용 공간을 만들어주세요.', '서울시 금천구', 0, 19, '반려동물 공원 설치 건의', 44, 3),
                                                                                                                       ('2026-04-07 09:00:00', '2026-04-07 09:00:00', '장마철에 침수 피해가 반복됩니다. 근본적인 배수 시설 개선이 필요합니다.', '서울시 동대문구', 0, 25, '침수 피해 예방 배수 시설 개선 요청', 60, 1),
                                                                                                                       ('2026-04-07 10:00:00', '2026-04-07 10:00:00', '지역 내 CCTV 사각지대가 많습니다. 범죄 예방을 위해 추가 설치가 시급합니다.', '서울시 서대문구', 0, 17, 'CCTV 추가 설치 요청', 41, 2);
INSERT INTO reply (created_at, updated_at, content, board_id, user_id) VALUES
                                                                           ('2026-04-01 10:30:00', '2026-04-01 10:30:00', '저도 같은 생각입니다. 빨리 개선됐으면 좋겠네요.', 1, 2),
                                                                           ('2026-04-01 11:30:00', '2026-04-01 11:30:00', '우리 동네도 같은 문제가 있습니다. 적극 지지합니다!', 1, 3),
                                                                           ('2026-04-01 12:30:00', '2026-04-01 12:30:00', '쓰레기통 부족 문제는 오래된 민원입니다. 빨리 해결되면 좋겠어요.', 2, 1),
                                                                           ('2026-04-01 13:30:00', '2026-04-01 13:30:00', '가로등 고장은 안전 문제입니다. 구청에 즉시 신고하세요.', 3, 1),
                                                                           ('2026-04-02 09:30:00', '2026-04-02 09:30:00', '주차 문제 정말 심각합니다. 공영주차장 꼭 필요해요.', 4, 2),
                                                                           ('2026-04-02 10:30:00', '2026-04-02 10:30:00', '어린이 보호구역 단속 카메라 설치 적극 찬성합니다.', 5, 3),
                                                                           ('2026-04-02 11:30:00', '2026-04-02 11:30:00', '버스 배차 간격 문제는 출퇴근 때마다 느낍니다.', 6, 1),
                                                                           ('2026-04-03 09:30:00', '2026-04-03 09:30:00', '산책로 정비가 시급합니다. 비 오면 진흙탕이 됩니다.', 7, 2),
                                                                           ('2026-04-03 10:30:00', '2026-04-03 10:30:00', '노인 프로그램 확대 정말 필요합니다. 어르신들이 갈 곳이 없어요.', 8, 3),
                                                                           ('2026-04-03 11:30:00', '2026-04-03 11:30:00', '청년 취업 지원 센터 꼭 필요합니다. 적극 찬성해요.', 9, 1),
                                                                           ('2026-04-04 09:30:00', '2026-04-04 09:30:00', '분리수거 시설 노후화 문제 공감합니다. 빨리 교체해주세요.', 10, 2),
                                                                           ('2026-04-04 10:30:00', '2026-04-04 10:30:00', '도서관 야간 운영 연장 정말 필요합니다. 직장인들은 낮에 못 가요.', 11, 3),
                                                                           ('2026-04-04 11:30:00', '2026-04-04 11:30:00', '학교 앞 불법 주정차 단속 강화 찬성합니다. 아이들이 위험해요.', 12, 1),
                                                                           ('2026-04-05 09:30:00', '2026-04-05 09:30:00', '공중화장실 위생 문제 오래된 불만입니다. 꼭 개선해주세요.', 13, 2),
                                                                           ('2026-04-05 10:30:00', '2026-04-05 10:30:00', '전통시장 주변 도로 좁은 거 진짜 불편합니다.', 14, 3),
                                                                           ('2026-04-05 11:30:00', '2026-04-05 11:30:00', 'ATM 없어서 불편한 거 맞습니다. 편의시설 확충 필요해요.', 15, 1),
                                                                           ('2026-04-06 09:30:00', '2026-04-06 09:30:00', '지역 문화 행사 정말 없죠. 동네 축제 생기면 좋겠어요.', 16, 2),
                                                                           ('2026-04-06 10:30:00', '2026-04-06 10:30:00', '자전거 도로 끊기는 문제 위험했던 경험 있습니다.', 17, 3),
                                                                           ('2026-04-06 11:30:00', '2026-04-06 11:30:00', '반려동물 공원 정말 필요합니다. 강아지 뛰어놀 곳이 없어요.', 18, 1),
                                                                           ('2026-04-07 09:30:00', '2026-04-07 09:30:00', '장마철 침수 문제 매년 반복됩니다. 근본적 해결이 필요해요.', 19, 2);
